from cryptography.fernet import Fernet
import os

# Generate and store this key in your application config
ENCRYPTION_KEY = os.environ.get('ENCRYPTION_KEY', Fernet.generate_key())
cipher_suite = Fernet(ENCRYPTION_KEY)

def encrypt_credit_card(card_number):
    """Encrypt credit card number for secure storage"""
    return cipher_suite.encrypt(card_number.encode())

def decrypt_credit_card(encrypted_card_number):
    """Decrypt credit card number for refund processing"""
    return cipher_suite.decrypt(encrypted_card_number).decode()